/**
 * Writes the generated knowledge sharing automation artifacts to disk under
 * the specified output directory. Depending on the chosen `language`, the
 * TypeScript or Python manager source is generated alongside a Markdown
 * overview, a JSON configuration file, and the appropriate dependency files
 * (`package.json` or `requirements.txt`). A Terraform scaffold file is always
 * generated regardless of language.
 *
 * @param config - The knowledge sharing automation configuration to render.
 * @param outputDir - Target directory where files will be written. It is
 *   created if it does not exist.
 * @param language - Target implementation language; `'typescript'` produces
 *   TypeScript artifacts, any other value produces Python artifacts.
 * @returns A Promise that resolves when all files have been written.
 */
export async function writeFiles(config: KnowledgeSharingAutomationConfig, outputDir: string, language: string): Promise<void> {
  const fs = await import('fs-extra');
  const path = await import('path');

  await fs.ensureDir(outputDir);

  const terraformCode = generateTerraformKnowledgeSharingAutomation(config);
  await fs.writeFile(path.join(outputDir, 'knowledge-sharing-automation.tf'), terraformCode);

  if (language === 'typescript') {
    const tsCode = generateTypeScriptKnowledgeSharingAutomation(config);
    await fs.writeFile(path.join(outputDir, 'knowledge-sharing-automation-manager.ts'), tsCode);

    const packageJson = {
      name: config.projectName + '-knowledge-sharing-automation',
      version: '1.0.0',
      description: 'Knowledge Sharing and Documentation Automation with AI Assistance',
      main: 'knowledge-sharing-automation-manager.ts',
      dependencies: { '@types/node': '^20.0.0' },
      devDependencies: { typescript: '^5.0.0', 'ts-node': '^10.0.0' },
    };
    await fs.writeFile(path.join(outputDir, 'package.json'), JSON.stringify(packageJson, null, 2));
  } else {
    const pyCode = generatePythonKnowledgeSharingAutomation(config);
    await fs.writeFile(path.join(outputDir, 'knowledge_sharing_automation_manager.py'), pyCode);

    const requirements = ['asyncio>=3.4.3', 'openai>=1.0.0', 'markdown>=3.5.0'];
    await fs.writeFile(path.join(outputDir, 'requirements.txt'), requirements.join('\n'));
  }

  const markdown = generateKnowledgeSharingAutomationMD(config);
  await fs.writeFile(path.join(outputDir, 'KNOWLEDGE_SHARING_AUTOMATION.md'), markdown);

  const configJson = {
    projectName: config.projectName,
    providers: config.providers,
    templates: config.templates,
    rules: config.rules,
    knowledgeBases: config.knowledgeBases,
    ai: config.ai,
    enableAutoGeneration: config.enableAutoGeneration,
    enableVersioning: config.enableVersioning,
    enableSync: config.enableSync,
  };
  await fs.writeFile(path.join(outputDir, 'knowledge-sharing-automation-config.json'), JSON.stringify(configJson, null, 2));
}

